hooks.command:
FILE=$(jq -r '.tool_input.file_path // empty'); if echo "$FILE" | grep -q '\.py$'; then python3 -c "
import ast, sys
try:
    with open('$FILE') as f:
        tree = ast.parse(f.read())
    for node in ast.walk(tree):
        if isinstance(node, ast.Call):
            func = getattr(node.func, 'attr', '') or getattr(node.func, 'id', '')
            if func in ['calculate', 'sum', 'mean', 'variance', 'average']:
                args = [getattr(a, 's', getattr(a, 'n', '')) for a in node.args]
except:
    pass
" 2>/dev/null || true; fi
